 886→      }));
 887→    case 'FIXTURE_UPDATE':
 888→      return updateFloor(state, action.floorId, f => ({
 889→        ...f,
 890→        fixtures: (f.fixtures || []).map(fix =>
 891→          fix.id === action.fixture.id ? { ...fix, ...action.fixture } : fix
 892→        ),
 893→      }));
 894→    case 'FIXTURE_DELETE':
 895→      return updateFloor(state, action.floorId, f => ({
 896→        ...f,
 897→        fixtures: (f.fixtures || []).filter(fix => fix.id !== action.fixtureId),
 898→      }));
 899→
 900→    case 'COLUMN_ADD':
 901→      return updateFloor(state, action.floorId, f => ({
 902→        ...f, columns: [...(f.columns || []), action.column],
 903→      }));
 904→    case 'COLUMN_DUPLICATE':
 905→      return updateFloor(state, action.floorId, f => ({
 906→        ...f,
 907→        columns: [...(f.columns || []), action.column],
 908→      }));
 909→    case 'COLUMN_UPDATE':
 910→      return updateFloor(state, action.floorId, f => {
 911→        const nextColumns = (f.columns || []).map(c => (
 912→          c.id === action.column.id ? { ...c, ...action.column } : c
 913→        ));
 914→        return {
 915→          ...f,
 916→          columns: nextColumns,
 917→          walls: f.walls.map(w => syncWallAttachmentPoints(w, nextColumns)),
 918→        };
 919→      });
 920→    case 'COLUMN_DELETE': {
 921→      const deletedCol = (f => (f.columns || []).find(c => c.id === action.columnId))(
 922→        state.project.floors.find(fl => fl.id === action.floorId) || {}
 923→      );
 924→      const colPoint = deletedCol ? { kind: 'point', x: deletedCol.x, y: deletedCol.y } : null;
 925→      return updateFloor(state, action.floorId, f => ({
 926→        ...f,
 927→        columns: (f.columns || []).filter(c => c.id !== action.columnId),
 928→        walls: f.walls.map(w => detachColumnAttachments(w, f.columns || [], action.columnId)),
 929→        beams: (f.beams || []).map(beam => {
 930→          const newStart = beam.startRef?.id === action.columnId && colPoint
 931→            ? { ...colPoint } : beam.startRef;
 932→          const newEnd = beam.endRef?.id === action.columnId && colPoint
 933→            ? { ...colPoint } : beam.endRef;
 934→          if (newStart === beam.startRef && newEnd === beam.endRef) return beam;
 935→          return { ...beam, startRef: newStart, endRef: newEnd };
 936→        }),
 937→      }));
 938→    }
 939→
 940→    case 'PHASE_ADD':
 941→      return applyProjectUpdate(state, {
 942→        ...state.project,
 943→        updatedAt: new Date().toISOString(),
 944→        phases: sortPhases([...(state.project.phases || []), action.phase]),
 945→      });
 946→
 947→    case 'PHASE_UPDATE':
 948→      return applyProjectUpdate(state, {
 949→        ...state.project,
 950→        updatedAt: new Date().toISOString(),
 951→        phases: sortPhases(
 952→          (state.project.phases || []).map(p =>
 953→            p.id === action.phase.id ? { ...p, ...action.phase } : p
 954→          )
 955→        ),
 956→      });
 957→
 958→    case 'PHASE_DELETE': {
 959→      const nextProject = clearProjectPhaseReferences(state.project, action.phaseId);
 960→      return applyProjectUpdate(state, {
 961→        ...nextProject,
 962→        updatedAt: new Date().toISOString(),
 963→        phases: (state.project.phases || []).filter((phase) => phase.id !== action.phaseId),
 964→      });
 965→    }
 966→
 967→    case 'PHASE_REORDER':
 968→      return applyProjectUpdate(state, {
 969→        ...state.project,
 970→        updatedAt: new Date().toISOString(),
 971→        phases: action.phases,
 972→      });
 973→
 974→    case 'MARK_SAVED':
 975→      return {
 976→        ...state,
 977→        isDirty: false,
 978→        lastSavedAt: new Date().toISOString(),
 979→        savedSnapshot: snapshotProject(state.project),
 980→      };
 981→
 982→    case 'UNDO': {
 983→      if (state.history.length === 0) return state;
 984→      const previousProject = state.history[state.history.length - 1];
 985→      return {
 986→        ...state,
 987→        project: previousProject,
 988→        history: state.history.slice(0, -1),
 989→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
 990→        isDirty: snapshotProject(previousProject) !== state.savedSnapshot,
 991→      };
 992→    }
 993→
 994→    case 'REDO': {
 995→      if (state.future.length === 0) return state;
 996→      const nextProject = state.future[0];
 997→      return {
 998→        ...state,
 999→        project: nextProject,
1000→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
1001→        future: state.future.slice(1),
1002→        isDirty: snapshotProject(nextProject) !== state.savedSnapshot,
1003→      };
1004→    }
1005→
1006→    default:
1007→      return state;
1008→  }
1009→}
