1022→export function ProjectProvider({ children }) {
1023→  const [state, dispatch] = useReducer(projectReducer, initialState);
1024→  return (
1025→    <ProjectContext.Provider value={{ state, dispatch }}>
1026→      {children}
1027→    </ProjectContext.Provider>
1028→  );
