1031→export function useProject() {
1032→  const ctx = useContext(ProjectContext);
1033→  if (!ctx) throw new Error('useProject must be used within ProjectProvider');
1034→  const { state, dispatch } = ctx;
1035→
1036→  const duplicateFloor = (floorId) => {
1037→    const floor = state.project.floors.find((entry) => entry.id === floorId) || null;
1038→    return floor ? createDuplicatedFloor(floor) : null;
1039→  };
1040→
1041→  return {
1042→    project: state.project,
1043→    isDirty: state.isDirty,
1044→    lastSavedAt: state.lastSavedAt,
1045→    canUndo: state.history.length > 0,
1046→    canRedo: state.future.length > 0,
1047→    dispatch,
1048→    duplicateFloor,
1049→    getFloor: (floorId) => state.project.floors.find(f => f.id === floorId),
1050→  };
1051→}
