 1→export const PHASE_ASSIGNABLE_KEYS = [
 2→  'walls', 'doors', 'windows', 'columns', 'beams', 'slabs',
 3→  'stairs', 'landings', 'fixtures', 'rooms', 'railings',
 4→];
 5→
 6→export function mapPhaseAssignableFloorObjects(floor, mapper) {
 7→  const nextFloor = { ...floor };
 8→
 9→  for (const key of PHASE_ASSIGNABLE_KEYS) {
10→    const objects = floor[key];
11→    if (!Array.isArray(objects)) continue;
12→    nextFloor[key] = objects.map((obj) => mapper(obj, { key, floor }));
13→  }
14→
15→  return nextFloor;
16→}
17→
18→export function countObjectsInProjectPhase(project, phaseId) {
19→  let count = 0;
20→
21→  for (const floor of project.floors || []) {
22→    for (const key of PHASE_ASSIGNABLE_KEYS) {
23→      for (const obj of floor[key] || []) {
24→        if (obj.phaseId === phaseId) count++;
25→      }
26→    }
27→  }
28→
29→  if (project?.roofSystem?.phaseId === phaseId) {
30→    count += 1;
31→  }
32→  for (const trussSystem of project?.trussSystems || []) {
33→    if (trussSystem.phaseId === phaseId) count += 1;
34→  }
35→
36→  return count;
37→}
38→
39→export function clearProjectPhaseReferences(project, phaseId) {
40→  return {
41→    ...project,
42→    floors: (project.floors || []).map((floor) => (
43→      mapPhaseAssignableFloorObjects(floor, (obj) => (
44→        obj.phaseId === phaseId ? { ...obj, phaseId: null } : obj
45→      ))
46→    )),
47→    roofSystem: project.roofSystem?.phaseId === phaseId
48→      ? { ...project.roofSystem, phaseId: null }
49→      : project.roofSystem,
50→    trussSystems: (project.trussSystems || []).map((trussSystem) => (
51→      trussSystem.phaseId === phaseId
52→        ? { ...trussSystem, phaseId: null }
53→        : trussSystem
54→    )),
55→    sheets: (project.sheets || []).map((sheet) => ({
56→      ...sheet,
